With $1$ rubber band, we can cover $3$ edges as shown below:

\begin{center}
\begin{asy}[labelstyle = +]
import roundedpath; size(12cm);
transform sh = shift(-1, -sqrt(3)/3); 
path t = sh*((0,0) -- (1,0) -- (1/2, sqrt(3)/2) -- cycle);
picture base;
for (int i = 0; i < 3; ++i)
{
  points.push(new pair[]);
  for (int j = 0; j < 3 - i; ++j)
  {
    points[i].push(sh*(j + i/2, i * sqrt(3)/2));
  }
  for (int j = 0; j < 2 - i; ++j)
  {
    draw(base, shift((j + i/2, i * sqrt(3)/2)) * t, linewidth(10) + grey);
  }
}
draw(base, roundedpath((points[0][0] + points[0][1]) / 2 -- points[0][1] -- (points[0][1] + points[1][1]) / 2, 0.15), red + linewidth(10));
\end{asy}
\end{center}

